import React from 'react';
import { motion } from "framer-motion";
import { Clock, CheckCircle, Loader2 } from "lucide-react";
import axios from 'axios';

const TaskCard = ({ task, refreshTasks }) => {
  const updateStatus = async () => {
    try {
      const token = localStorage.getItem('token');
      await axios.patch(`http://localhost:5000/api/tasks/${task._id}`, 
        { status: 'Completed' },
        { headers: { 'x-auth-token': token } }
      );
      refreshTasks();
    } catch (err) { console.log(err); }
  };

  return (
    <motion.div
      whileHover={{ y: -5 }}
      className="p-6 bg-white/5 border border-white/10 rounded-3xl backdrop-blur-lg shadow-xl"
    >
      <div className="flex justify-between items-start mb-4">
        <h3 className="text-xl font-bold text-white">{task.title}</h3>
        <span className={`text-[10px] px-2 py-1 rounded-md ${task.status === 'Completed' ? 'bg-green-500/20 text-green-400' : 'bg-yellow-500/20 text-yellow-400'}`}>
          {task.status}
        </span>
      </div>
      <p className="text-gray-400 text-sm mb-4 line-clamp-2">{task.description}</p>
      
      <div className="flex items-center justify-between pt-4 border-t border-white/10">
        <div className="flex items-center gap-2 text-xs text-gray-500">
          <Clock size={14} />
          <span>{task.priority} Priority</span>
        </div>
        
        {task.status !== 'Completed' && (
          <button 
            onClick={updateStatus}
            className="flex items-center gap-1 text-xs font-bold bg-indigo-600 px-3 py-2 rounded-xl hover:bg-indigo-500 transition-all"
          >
            <CheckCircle size={14} /> Done
          </button>
        )}
      </div>
    </motion.div>
  );
};

export default TaskCard;
